 1	import * as React from 'react';
 2	import { Button, ButtonVariant, FormSelect, FormSelectOption, TextInput } from '@patternfly/react-core';
 3	import { Td, Tr } from '@patternfly/react-table';
 4	import { Address } from '../../../types/IstioObjects';
 5	import { isValid } from 'utils/Common';
 6	import { isGatewayHostValid, isValidIp } from '../../../utils/IstioConfigUtils';
 7	import { KialiIcon } from 'config/KialiIcon';
 8	
 9	type AddressBuilderProps = {
10	  address: Address;
11	  index: number;
12	  onRemoveAddress: (i: number) => void;
13	  onChange: (address: Address, i: number) => void;
14	};
15	
16	export const isValidAddress = (address: Address): boolean => {
17	  if (address.type === addressTypes[0]) {
18	    return isValidIp(address.value);
19	  }
20	
21	  if (address.type === addressTypes[1]) {
22	    return isGatewayHostValid(address.value);
23	  }
24	
25	  return false;
26	};
27	
28	export const addressTypes = ['IPAddress', 'Hostname'];
29	
30	export const AddressBuilder: React.FC<AddressBuilderProps> = (props: AddressBuilderProps) => {
31	  const onAddValue = (_event: React.FormEvent, value: string): void => {
32	    const l = props.address;
33	    l.value = value.trim();
34	
35	    props.onChange(l, props.index);
36	  };
37	
38	  const onAddType = (_event: React.FormEvent, value: string): void => {
39	    const l = props.address;
40	    l.type = value.trim();
41	
42	    props.onChange(l, props.index);
43	  };
44	
45	  return (
46	    <Tr>
47	      <Td>
48	        <FormSelect value={props.address.type} id={`addType_${props.index}`} name="addType" onChange={onAddType}>
49	          {addressTypes.map((option, index) => (
50	            <FormSelectOption isDisabled={false} key={`p_${index}`} value={option} label={option} />
51	          ))}
52	        </FormSelect>
53	      </Td>
54	
55	      <Td>
56	        <TextInput
57	          value={props.address.value}
58	          type="text"
59	          id={`addValue_${props.index}`}
60	          aria-describedby="add value"
61	          name="addVale"
62	          onChange={onAddValue}
63	          validated={isValid(isValidAddress(props.address))}
64	        />
65	      </Td>
66	
67	      <Td>
68	        <Button
69	          id="deleteBtn"
70	          variant={ButtonVariant.link}
71	          icon={<KialiIcon.Trash />}
72	          style={{ padding: 0 }}
73	          onClick={() => props.onRemoveAddress(props.index)}
74	        />
75	      </Td>
76	    </Tr>
77	  );
78	};

